      Some((c, bl))
    } else {
      None
    }
  }.flatten
  val sorted = validCoupons.sortWith { (a, b) =>
    val aOrder = businessOrderMap(a._2)
    val bOrder = businessOrderMap(b._2)
    if (aOrder != bOrder) aOrder < bOrder else a._1 < b._1
  }
  sorted.map { case (code, _) => code }
}
